function solve(nums: number[], k: number): number {
    const n = nums.length;
    const dp = new Array(n + 1).fill(0);
    let prefixSum = 0;
    const modMap: { [key: number]: number } = {};
    modMap[0] = 0;

    for (let i = 1; i <= n; i++) {
        prefixSum += nums[i - 1];
        const mod = prefixSum % k;
        let min_prev = Infinity;
        if (mod in modMap) {
            min_prev = modMap[mod];
        }
        dp[i] = Math.min(dp[i - 1] + nums[i - 1], min_prev);
        if (mod in modMap) {
            if (dp[i] < modMap[mod]) {
                modMap[mod] = dp[i];
            }
        } else {
            modMap[mod] = dp[i];
        }
    }
    return dp[n];
}
